const body = $input.first().json.body || $input.first().json;

// Extrai dados da mensagem recebida (formato Evolution API)
const numeroReceptor = body.instance || body.to || '';
const numeroRemetente = body.data?.key?.remoteJid?.replace('@s.whatsapp.net', '') || '';
const mensagemTexto = body.data?.message?.conversation 
  || body.data?.message?.extendedTextMessage?.text 
  || '';
const messageId = body.data?.key?.id || '';
const timestamp = body.data?.messageTimestamp || Math.floor(Date.now() / 1000);

// Identifica a unidade
const unidade = UNIDADES[numeroReceptor] || null;

if (!unidade) {
  throw new Error(`Número receptor não mapeado: ${numeroReceptor}`);
}

return [{
  json: {
    // Dados da mensagem
    numero_remetente: numeroRemetente,
    numero_receptor: numeroReceptor,
    mensagem: mensagemTexto,
    message_id: messageId,
    timestamp,
    // Contexto da unidade
    ...unidade,
    // Flag para próximas etapas
    processado: false
  }
}];

const dados = $input.first().json;

// Timezone Brasil (UTC-4 ou UTC-3 dependendo da época)
// Ajuste conforme necessário para cada unidade
const agora = new Date();
const horaBrasilia = new Date(agora.toLocaleString('en-US', { timeZone: 'America/Cuiaba' }));
const hora = horaBrasilia.getHours();
const diaSemana = horaBrasilia.getDay(); // 0=Dom, 1=Seg ... 6=Sáb

let dentroDoHorario = false;
let motivoFora = '';

if (diaSemana === 0) {
  // Domingo — sempre fora do horário
  dentroDoHorario = false;
  motivoFora = 'domingo';
} else if (diaSemana === 6) {
  // Sábado
  const abre = dados.horario_abertura_sabado;
  const fecha = dados.horario_fechamento_sabado;
  dentroDoHorario = hora >= abre && hora < fecha;
  motivoFora = `sábado — atendemos das ${abre}:00 às ${fecha}:00`;
} else {
  // Segunda a sexta
  const abre = dados.horario_abertura_semana;
  const fecha = dados.horario_fechamento_semana;
  dentroDoHorario = hora >= abre && hora < fecha;
  motivoFora = `atendemos de segunda a sexta das ${abre}:00 às ${fecha}:00`;
}

return [{
  json: {
    ...dados,
    dentro_do_horario: dentroDoHorario,
    motivo_fora_horario: motivoFora,
    hora_atual: hora,
    dia_semana: diaSemana
  }
}];

const dados = $input.first().json;
const nome = dados.nome_lead || '';
const saudacao = nome ? `Olá, ${nome}!` : 'Olá!';

return [{
  json: {
    ...dados,
    resposta_final: `${saudacao} Recebemos sua mensagem 💜\n\nNosso horário de atendimento é:\n📅 Segunda a sexta: ${dados.horario_semana}\n📅 Sábados: ${dados.horario_sabado}\n\nRetornaremos assim que abrirmos. Até lá!`,
    tipo_resposta: 'FORA_HORARIO',
    escalar: false
  }
}];

const dados = $input.first().json;

const fs = require('fs');
let systemPrompt = fs.readFileSync(
  '/home/iara/clients/Crystal-Laser/agents/sdr_system_prompt.md',
  'utf8'
);

// Injeta variáveis de contexto da unidade
systemPrompt = systemPrompt
  .replaceAll('{{unidade_nome}}', dados.unidade_nome)
  .replaceAll('{{cidade}}', dados.cidade)
  .replaceAll('{{horario_semana}}', dados.horario_semana)
  .replaceAll('{{horario_sabado}}', dados.horario_sabado)
  .replaceAll('{{nome_lead}}', dados.nome_lead || '')
  .replaceAll('{{estagio_lead}}', dados.estagio_lead || 'NOVO');

// Monta o histórico de mensagens para a API do Claude
const messages = dados.historico_mensagens || [{ role: 'user', content: dados.mensagem }];

return [{
  json: {
    ...dados,
    system_prompt_final: systemPrompt,
    messages_payload: messages
  }
}];

const dados = $input.first().json;
const claudeResponse = dados.content?.[0]?.text || '';

// Detecta tags de controle emitidas pelo agente
const escalarHumano = claudeResponse.includes('[ESCALAR_HUMANO]');
const escalarMenor = claudeResponse.includes('[ESCALAR_MENOR]');
const encerrarVitiligo = claudeResponse.includes('[ENCERRAR_VITILIGO]');
const agendar = claudeResponse.includes('[AGENDAR]');
const followUp = claudeResponse.includes('[FOLLOW_UP]');

// Remove tags da mensagem final antes de enviar para o lead
const respostaLimpa = claudeResponse
  .replace(/\[ESCALAR_HUMANO\]/g, '')
  .replace(/\[ESCALAR_MENOR\]/g, '')
  .replace(/\[ENCERRAR_VITILIGO\]/g, '')
  .replace(/\[AGENDAR\]/g, '')
  .replace(/\[FOLLOW_UP\]/g, '')
  .trim();

// Determina ação principal
let acao_principal = 'CONTINUAR';
if (escalarHumano) acao_principal = 'ESCALAR_HUMANO';
else if (escalarMenor) acao_principal = 'ESCALAR_MENOR';
else if (encerrarVitiligo) acao_principal = 'ENCERRAR_VITILIGO';
else if (agendar) acao_principal = 'AGENDAR';
else if (followUp) acao_principal = 'FOLLOW_UP';

return [{
  json: {
    numero_remetente: dados.numero_remetente,
    numero_receptor: dados.numero_receptor,
    unidade_nome: dados.unidade_nome,
    google_calendar_id: dados.google_calendar_id,
    nome_lead: dados.nome_lead,
    resposta_final: respostaLimpa,
    acao_principal,
    tags: { escalarHumano, escalarMenor, encerrarVitiligo, agendar, followUp },
    historico_mensagens_atualizado: [
      ...(dados.historico_mensagens || []),
      { role: 'assistant', content: respostaLimpa }
    ]
  }
}];

const dados = $input.first().json;

// Calcula próxima tentativa de follow-up (24h)
const proxima = new Date();
proxima.setHours(proxima.getHours() + 24);

// TODO: salvar na base de dados para o workflow de follow-up separado
console.log(`[FOLLOW_UP] Agendado para: ${proxima.toISOString()} | Lead: ${dados.numero_remetente}`);

return [{
  json: {
    ...dados,
    follow_up_agendado_para: proxima.toISOString()
  }
}];

const dados = $input.first().json;

// O nó Redis "Get" retorna o valor em dados.value (string JSON ou null)
const valorRedis = dados.value || null;

let historico;

if (valorRedis) {
  // Lead conhecido — restaura histórico existente
  try {
    historico = JSON.parse(valorRedis);
  } catch (e) {
    // JSON corrompido — trata como lead novo
    historico = null;
  }
}

if (!historico) {
  // Lead novo — estrutura base
  historico = {
    nome_lead: '',
    estagio_lead: 'NOVO',
    vitiligo_verificado: false,
    area_interesse: '',
    combo_apresentado: '',
    forma_pagamento_escolhida: '',
    historico_mensagens: [],
    flags: [],
    criado_em: new Date().toISOString(),
  };
}

// Limita histórico a 20 mensagens para não estourar o context window do Claude
// Mantém sempre as primeiras 2 (contexto inicial) + as últimas 18
const msgs = historico.historico_mensagens || [];
const historicoLimitado = msgs.length > 20
  ? [...msgs.slice(0, 2), ...msgs.slice(-18)]
  : msgs;

// Adiciona mensagem atual do lead
const historicoComMensagemAtual = [
  ...historicoLimitado,
  {
    role: 'user',
    content: dados.mensagem,
    timestamp: new Date().toISOString()
  }
];

return [{
  json: {
    // Dados originais da mensagem
    numero_remetente: dados.numero_remetente,
    numero_receptor: dados.numero_receptor,
    mensagem: dados.mensagem,
    message_id: dados.message_id,
    // Contexto da unidade
    unidade_nome: dados.unidade_nome,
    cidade: dados.cidade,
    horario_semana: dados.horario_semana,
    horario_sabado: dados.horario_sabado,
    horario_abertura_semana: dados.horario_abertura_semana,
    horario_fechamento_semana: dados.horario_fechamento_semana,
    horario_abertura_sabado: dados.horario_abertura_sabado,
    horario_fechamento_sabado: dados.horario_fechamento_sabado,
    google_calendar_id: dados.google_calendar_id,
    // Histórico restaurado do Redis
    nome_lead: historico.nome_lead || '',
    estagio_lead: historico.estagio_lead || 'NOVO',
    vitiligo_verificado: historico.vitiligo_verificado || false,
    area_interesse: historico.area_interesse || '',
    combo_apresentado: historico.combo_apresentado || '',
    forma_pagamento_escolhida: historico.forma_pagamento_escolhida || '',
    flags: historico.flags || [],
    historico_mensagens: historicoComMensagemAtual,
    // Chave Redis para o nó 11 usar ao salvar
    redis_chave: `cl_hist_${dados.numero_remetente}_${dados.numero_receptor}`,
  }
}];

const dados = $input.first().json;

const motivos = {
  'ESCALAR_HUMANO': '⚠️ FECHAMENTO / CANCELAMENTO / RECLAMAÇÃO',
  'ESCALAR_MENOR':  '👧 PROTOCOLO MENOR DE IDADE (filha ≤ 14 anos)',
};

const motivo = motivos[dados.acao_principal] || '⚠️ ESCALONAMENTO';

const mensagem = 
`🔔 *CRYSTAL LASER ${dados.unidade_nome.toUpperCase()}*
${motivo}

👤 *Lead:* ${dados.nome_lead || 'Não identificado'}
📱 *WhatsApp:* ${dados.numero_remetente}
🎯 *Área de interesse:* ${dados.area_interesse || 'Não informada'}
📋 *Estágio:* ${dados.estagio_lead || 'NOVO'}

💬 *Última mensagem do lead:*
"${dados.mensagem}"

👆 Entre em contato agora para dar continuidade ao atendimento.`;

return [{
  json: {
    ...dados,
    numero_notificacao: dados.numero_notificacao,
    mensagem_notificacao: mensagem,
    notificacao_montada: true,
  }
}];

const dados = $input.first().json;

const INSTANCIAS = {
  '556699884352': 'crystal-sinop',
  '556584040024': 'crystal-cuiaba',
  '556699220642': 'crystal-sorriso',
  '556598011102': 'crystal-varzea',
