    ...dados,
    evolution_instancia: instancia,
    evolution_url: `http://31.97.93.103:8080/message/sendText/${instancia}`,
    evolution_apikey: 'iara-evo-key-2026',
  }
}];

const dados = $input.first().json;

// Extrai novos metadados da resposta do agente para atualizar o histórico
// O agente pode ter identificado o nome, área, estágio etc. nas mensagens
const historicoParaSalvar = {
  nome_lead: dados.nome_lead || '',
  estagio_lead: dados.estagio_lead || 'NOVO',
  vitiligo_verificado: dados.vitiligo_verificado || false,
  area_interesse: dados.area_interesse || '',
  combo_apresentado: dados.combo_apresentado || '',
  forma_pagamento_escolhida: dados.forma_pagamento_escolhida || '',
  flags: dados.flags || [],
  historico_mensagens: dados.historico_mensagens_atualizado || [],
  atualizado_em: new Date().toISOString(),
};

return [{
  json: {
    redis_chave: dados.redis_chave,
    redis_valor: JSON.stringify(historicoParaSalvar),
    redis_ttl: 2592000, // 30 dias em segundos
    // Passa adiante para o webhook de resposta
    sucesso: true,
  }
}];
